// Reveal the closed spec fns the postcondition uses so z3 can bridge from
// the method calls in the ensures (e.g. `allocated_pages_4k()`) to the raw
// `@` field views that `det_..._equal` compares.
reveal(PageAllocator::allocated_pages_4k);
reveal(PageAllocator::allocated_pages_2m);
reveal(PageAllocator::allocated_pages_1g);
reveal(PageAllocator::mapped_pages_4k);
reveal(PageAllocator::mapped_pages_2m);
reveal(PageAllocator::mapped_pages_1g);
reveal(PageAllocator::page_mappings);
reveal(PageAllocator::page_io_mappings);

// Pull each `container_map_*@` ensures into the proof context for both runs.
// Both `post1_self_` and `post2_self_` are forced to equal the same RHS,
// which is built entirely from `pre_self_`; sequence/map extensionality
// (=~=) then lifts that to direct map-view equality.
let oc = pre_self_.page_array@[page_ptr2page_index(target_ptr) as int]
    .owning_container.unwrap();
let upd_set = pre_self_.container_map_4k@[oc].remove(target_ptr);
let target_cm4k = pre_self_.container_map_4k@.insert(oc, upd_set);

assert(post1_self_.container_map_4k@ =~= target_cm4k);
assert(post2_self_.container_map_4k@ =~= target_cm4k);
assert(post1_self_.container_map_4k@ =~= post2_self_.container_map_4k@);
assert(post1_self_.container_map_4k@ == post2_self_.container_map_4k@);

assert(post1_self_.container_map_2m@ =~= pre_self_.container_map_2m@);
assert(post2_self_.container_map_2m@ =~= pre_self_.container_map_2m@);
assert(post1_self_.container_map_2m@ =~= post2_self_.container_map_2m@);
assert(post1_self_.container_map_2m@ == post2_self_.container_map_2m@);

assert(post1_self_.container_map_1g@ =~= pre_self_.container_map_1g@);
assert(post2_self_.container_map_1g@ =~= pre_self_.container_map_1g@);
assert(post1_self_.container_map_1g@ =~= post2_self_.container_map_1g@);
assert(post1_self_.container_map_1g@ == post2_self_.container_map_1g@);

// Bridge `allocated_pages_*()` method-call equalities (from the ensures)
// to `(post*_self_.allocated_pages_*)@` field-view equalities that
// `det_..._equal` actually checks.  The reveals above unfold the closed
// spec fns to `self.allocated_pages_*@`, so the chain closes.
assert(post1_self_.allocated_pages_4k() =~= pre_self_.allocated_pages_4k());
assert(post2_self_.allocated_pages_4k() =~= pre_self_.allocated_pages_4k());
assert(post1_self_.allocated_pages_4k() =~= post2_self_.allocated_pages_4k());
assert((post1_self_.allocated_pages_4k)@ =~= (post2_self_.allocated_pages_4k)@);
assert((post1_self_.allocated_pages_4k)@ == (post2_self_.allocated_pages_4k)@);

assert(post1_self_.allocated_pages_2m() =~= pre_self_.allocated_pages_2m());
assert(post2_self_.allocated_pages_2m() =~= pre_self_.allocated_pages_2m());
assert(post1_self_.allocated_pages_2m() =~= post2_self_.allocated_pages_2m());
assert((post1_self_.allocated_pages_2m)@ =~= (post2_self_.allocated_pages_2m)@);
assert((post1_self_.allocated_pages_2m)@ == (post2_self_.allocated_pages_2m)@);

assert(post1_self_.allocated_pages_1g() =~= pre_self_.allocated_pages_1g());
assert(post2_self_.allocated_pages_1g() =~= pre_self_.allocated_pages_1g());
assert(post1_self_.allocated_pages_1g() =~= post2_self_.allocated_pages_1g());
assert((post1_self_.allocated_pages_1g)@ =~= (post2_self_.allocated_pages_1g)@);
assert((post1_self_.allocated_pages_1g)@ == (post2_self_.allocated_pages_1g)@);

// `r1` and `r2` are both unit `()`, so their equality is structural.
assert(r1 == r2);
